const score = 78;

if (score >= 90) {
  console.log("ممتاز 🏆");
} else if (score >= 75) {
  console.log("جيد جدًا 🥇");
} else if (score >= 60) {
  console.log("جيد 👍");
} else {
  console.log("يحتاج مذاكرة 📖");
}

const userName = "";

if (userName) {
  console.log("أهلًا " + userName);
} else {
  console.log("لم تدخل اسمًا!");
}

console.log(Boolean("0"));  // true نص غير فارغ
console.log(Boolean(0));      // false

const day = "الجمعة";

switch (day) {
  case "الجمعة":
  case "السبت":
    console.log("عطلة نهاية الأسبوع 🎉");
    break;
  case "الأحد":
    console.log("بداية أسبوع العمل");
    break;
  default:
    console.log("يوم عمل عادي");
}
